private void tdCostCenter_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
  // --- Declare values ---
decimal stained = 0;
decimal sampleQty = 0;

// --- Read values ---
if (GetCurrentColumnValue("Stained") != null)
    stained = Convert.ToDecimal(GetCurrentColumnValue("Stained"));

if (GetCurrentColumnValue("SampleQty") != null)
    sampleQty = Convert.ToDecimal(GetCurrentColumnValue("SampleQty"));

// --- Equation ---
decimal percentage = 0;
if (sampleQty > 0)
    percentage = (stained * 100m) / sampleQty;

// --- Add to report totals (for average) ---
decimal StainedPercReportSum = 0;
int StainedPercReportCount = 0;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.##"); // format with up to 2 decimals
StainedPercReportSum += percentage;   // sum of percentages
StainedPercReportCount++;             // count how many percentages added

// --- Compute running average ---
decimal avgPercentage = 0;
if (StainedPercReportCount > 0)
    avgPercentageStained = StainedPercReportSum / StainedPercReportCount;


}

private void xrTableCell43_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    xrTableCell43.Text = avgPercentageStained.ToString("N2");

}

