private void xrTableCell21_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal slabSides = 0;
decimal bodyCheck = 0;
decimal wrinkled = 0;
decimal thinSpot = 0;
decimal sampleQty = 0;

// --- Read values ---
if (GetCurrentColumnValue("SlabSides") != null)
    slabSides = Convert.ToDecimal(GetCurrentColumnValue("SlabSides"));

if (GetCurrentColumnValue("BodyCheck") != null)
    bodyCheck = Convert.ToDecimal(GetCurrentColumnValue("BodyCheck"));

if (GetCurrentColumnValue("Wrinkled") != null)
    wrinkled = Convert.ToDecimal(GetCurrentColumnValue("Wrinkled"));

if (GetCurrentColumnValue("ThinSpot") != null)
    thinSpot = Convert.ToDecimal(GetCurrentColumnValue("ThinSpot"));

if (GetCurrentColumnValue("SampleQty") != null)
    sampleQty = Convert.ToDecimal(GetCurrentColumnValue("SampleQty"));

// --- Equation ---
decimal percentage = 0;
if (sampleQty > 0)
    percentage = ((slabSides + bodyCheck + wrinkled + thinSpot) * 100m) / sampleQty;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.##"); // format with up to 2 decimals
// --- Add to report totals (for average) ---
TotalShellDefectsPercSum += percentage;   // sum of combined percentages
TotalShellDefectsPercCount++;             // count of rows

// --- Compute running average ---
if (TotalShellDefectsPercCount > 0)
    avgPercentageShellDefects = TotalShellDefectsPercSum / TotalShellDefectsPercCount;



}

